// ===== CONFIGURAÇÕES DO NEGÓCIO =====
const HORARIO_ABERTURA = 6;   // 09:00
const HORARIO_FECHAMENTO = 18; // 18:00
const DURACAO_MINUTOS = 30;   // duração padrão do serviço

// ===== DADOS DE ENTRADA =====
const data = $json.data;   // YYYY-MM-DD
const hora = $json.hora;   // HH:mm

if (!data || !hora) {
  return [{
    valido: false,
    motivo: 'dados_incompletos'
  }];
}

// ===== CRIA DATETIME =====
const [ano, mes, dia] = data.split('-').map(Number);
const [h, m] = hora.split(':').map(Number);

const inicio = new Date(ano, mes - 1, dia, h, m);
const fim = new Date(inicio.getTime() + DURACAO_MINUTOS * 60000);

// ===== VALIDA HORÁRIO COMERCIAL =====
if (h < HORARIO_ABERTURA || fim.getHours() > HORARIO_FECHAMENTO) {
  return [{
    valido: false,
    motivo: 'fora_do_horario'
  }];
}

// ===== VALIDA DATA NO PASSADO =====
const agora = new Date();
if (inicio < agora) {
  return [{
    valido: false,
    motivo: 'data_passada'
  }];
}

// ===== SE PASSAR POR TUDO =====
return [{
  valido: true,
  inicio: inicio.toISOString(),
  fim: fim.toISOString()
}];

