const data = $json.data;
const hora = $json.hora;

// validação obrigatória
if (!data || !hora) {
  throw new Error('Data ou hora não informadas para criação do evento');
}

// normalizar hora (HH:mm)
let horaNormalizada = hora;

// se vier HH:mm:ss → corta
if (horaNormalizada.length === 8) {
  horaNormalizada = horaNormalizada.slice(0,5);
}

// se vier só HH → transforma em HH:00
if (/^\d{2}$/.test(horaNormalizada)) {
  horaNormalizada = `${horaNormalizada}:00`;
}

// valida formato final
if (!/^\d{2}:\d{2}$/.test(horaNormalizada)) {
  throw new Error(`Formato de hora inválido: ${hora}`);
}

// cria datas
const start = new Date(`${data}T${horaNormalizada}:00-03:00`);

if (isNaN(start.getTime())) {
  throw new Error(`Data inválida gerada: ${data} ${horaNormalizada}`);
}

// duração fixa: 30 min
const end = new Date(start.getTime() + 30 * 60 * 1000);

return [{
  startDateTime: start.toISOString(),
  endDateTime: end.toISOString(),
  horaNormalizada
}];

